package com.cho2hand.marketplace.controller.admin; import com.cho2hand.marketplace.dto.report.AdminReportResponse;import com.cho2hand.marketplace.service.admin.AdminService;import jakarta.validation.constraints.Positive;import java.util.*;import org.springframework.http.HttpStatus;import org.springframework.security.core.annotation.AuthenticationPrincipal;import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/v1/admin") public class AdminController{private final AdminService service;public AdminController(AdminService s){service=s;}@GetMapping("/reports")public List<AdminReportResponse> reports(){return service.reports();}@PatchMapping("/listings/{id}/archive")@ResponseStatus(HttpStatus.NO_CONTENT)public void archive(@PathVariable @Positive Long id){service.archive(id);}@PatchMapping("/reports/{id}/dismiss")@ResponseStatus(HttpStatus.NO_CONTENT)public void dismiss(@AuthenticationPrincipal Long admin,@PathVariable @Positive Long id){service.resolve(admin,id,false);}@PatchMapping("/reports/{id}/archive")@ResponseStatus(HttpStatus.NO_CONTENT)public void resolveAndArchive(@AuthenticationPrincipal Long admin,@PathVariable @Positive Long id){service.resolve(admin,id,true);}}
